import os
import io
import json
import uuid
import time
import threading
from typing import Optional, List, Dict, Any

import numpy as np
import pandas as pd
from PIL import Image

from flask import Flask, request, jsonify, send_from_directory
from werkzeug.utils import secure_filename

import tensorflow as tf
from tensorflow.keras import layers, models


BASE_DIR = os.path.abspath(os.path.dirname(__file__))
DATA_DIR = os.path.join(BASE_DIR, "data")
UPLOAD_DIR = os.path.join(DATA_DIR, "uploads")
CSV_DIR = os.path.join(DATA_DIR, "csv")
IMAGE_DIR = os.path.join(DATA_DIR, "images")
MODEL_DIR = os.path.join(BASE_DIR, "model")
os.makedirs(UPLOAD_DIR, exist_ok=True)
os.makedirs(CSV_DIR, exist_ok=True)
os.makedirs(IMAGE_DIR, exist_ok=True)
os.makedirs(MODEL_DIR, exist_ok=True)

MODEL_PATH = os.path.join(MODEL_DIR, "image_classifier.keras")
META_PATH = os.path.join(MODEL_DIR, "metadata.json")

app = Flask(__name__)
app.config["MAX_CONTENT_LENGTH"] = 200 * 1024 * 1024

train_lock = threading.Lock()
current_training = {"running": False, "status": "idle", "message": "", "started_at": None, "ended_at": None}


def _json_error(message: str, code: int = 400):
    return jsonify({"ok": False, "error": message}), code


def _save_metadata(meta: Dict[str, Any]):
    with open(META_PATH, "w", encoding="utf-8") as f:
        json.dump(meta, f, indent=2)


def _load_metadata() -> Dict[str, Any]:
    if os.path.exists(META_PATH):
        with open(META_PATH, "r", encoding="utf-8") as f:
            return json.load(f)
    return {"classes": [], "num_classes": 0, "input_shape": [128, 128, 3], "last_trained": None, "samples": 0}


def _ensure_model(input_shape=(128, 128, 3), num_classes=2, class_names: Optional[List[str]] = None):
    if os.path.exists(MODEL_PATH):
        return tf.keras.models.load_model(MODEL_PATH)
    return build_model(input_shape=input_shape, num_classes=num_classes, class_names=class_names)


def build_model(input_shape=(128, 128, 3), num_classes=2, class_names: Optional[List[str]] = None):
    inputs = layers.Input(shape=input_shape)
    x = layers.Rescaling(1.0 / 255)(inputs)
    x = layers.Conv2D(32, 3, activation="relu")(x)
    x = layers.MaxPooling2D()(x)
    x = layers.Conv2D(64, 3, activation="relu")(x)
    x = layers.MaxPooling2D()(x)
    x = layers.Conv2D(128, 3, activation="relu")(x)
    x = layers.MaxPooling2D()(x)
    x = layers.Dropout(0.25)(x)
    x = layers.Flatten()(x)
    x = layers.Dense(128, activation="relu")(x)
    x = layers.Dropout(0.5)(x)
    outputs = layers.Dense(num_classes, activation="softmax")(x)
    model = models.Model(inputs, outputs)
    model.compile(
        optimizer=tf.keras.optimizers.Adam(learning_rate=1e-3),
        loss="sparse_categorical_crossentropy",
        metrics=["accuracy"],
    )
    return model


def allowed_file(filename: str, allowed_extensions: set):
    return "." in filename and filename.rsplit(".", 1)[1].lower() in allowed_extensions


def save_uploaded_file(file_storage, target_dir: str, allowed_extensions: set) -> str:
    filename = secure_filename(file_storage.filename or "")
    if not filename:
        raise ValueError("Missing filename")
    if not allowed_file(filename, allowed_extensions):
        raise ValueError(f"Unsupported file type: {filename}")
    ext = filename.rsplit(".", 1)[1].lower()
    unique_name = f"{uuid.uuid4().hex}.{ext}"
    path = os.path.join(target_dir, unique_name)
    file_storage.save(path)
    return path


def load_csv_dataset(csv_path: str):
    df = pd.read_csv(csv_path)
    if "label" not in df.columns:
        raise ValueError("CSV must contain a 'label' column")
    feature_cols = [c for c in df.columns if c != "label"]
    if not feature_cols:
        raise ValueError("CSV must contain feature columns")
    X = df[feature_cols].values.astype(np.float32)
    y = df["label"].values
    if y.dtype.kind not in {"i", "u"}:
        classes = sorted(pd.unique(y).tolist())
        class_to_idx = {c: i for i, c in enumerate(classes)}
        y = np.array([class_to_idx[v] for v in y], dtype=np.int32)
        return X, y, classes
    return X, y.astype(np.int32), None


def load_image_dataset_from_dir(image_dir: str, target_size=(128, 128)):
    class_names = sorted([d for d in os.listdir(image_dir) if os.path.isdir(os.path.join(image_dir, d))])
    if not class_names:
        raise ValueError("No class folders found in image directory")
    images = []
    labels = []
    for idx, class_name in enumerate(class_names):
        class_dir = os.path.join(image_dir, class_name)
        for fname in os.listdir(class_dir):
            fpath = os.path.join(class_dir, fname)
            if os.path.isfile(fpath) and allowed_file(fname, {"jpg", "jpeg", "png", "bmp", "webp"}):
                img = Image.open(fpath).convert("RGB").resize(target_size)
                images.append(np.array(img, dtype=np.float32))
                labels.append(idx)
    if not images:
        raise ValueError("No images found")
    X = np.stack(images, axis=0)
    y = np.array(labels, dtype=np.int32)
    return X, y, class_names


def load_uploaded_image(file_storage, target_size=(128, 128)):
    data = file_storage.read()
    img = Image.open(io.BytesIO(data)).convert("RGB").resize(target_size)
    return np.array(img, dtype=np.float32)


def train_image_model_from_directory(image_dir: str, epochs: int = 5, batch_size: int = 32):
    X, y, class_names = load_image_dataset_from_dir(image_dir)
    num_classes = len(class_names)
    model = build_model(input_shape=X.shape[1:], num_classes=num_classes, class_names=class_names)
    callbacks = [
        tf.keras.callbacks.EarlyStopping(monitor="loss", patience=2, restore_best_weights=True),
    ]
    history = model.fit(X, y, epochs=epochs, batch_size=batch_size, validation_split=0.2 if len(X) >= 10 else 0.0, callbacks=callbacks, verbose=0)
    model.save(MODEL_PATH)
    meta = {
        "classes": class_names,
        "num_classes": num_classes,
        "input_shape": list(X.shape[1:]),
        "last_trained": time.time(),
        "samples": int(len(X)),
        "history": {k: [float(v) for v in vals] for k, vals in history.history.items()},
    }
    _save_metadata(meta)
    return meta


def train_csv_model(csv_path: str, epochs: int = 10, batch_size: int = 32):
    X, y, classes = load_csv_dataset(csv_path)
    input_shape = (X.shape[1],)
    num_classes = int(len(np.unique(y)))
    model = models.Sequential([
        layers.Input(shape=input_shape),
        layers.Normalization(),
        layers.Dense(64, activation="relu"),
        layers.Dense(64, activation="relu"),
        layers.Dense(num_classes, activation="softmax"),
    ])
    model.layers[1].adapt(X)
    model.compile(optimizer="adam", loss="sparse_categorical_crossentropy", metrics=["accuracy"])
    history = model.fit(X, y, epochs=epochs, batch_size=batch_size, validation_split=0.2 if len(X) >= 10 else 0.0, verbose=0)
    csv_model_path = os.path.join(MODEL_DIR, "tabular_model.keras")
    model.save(csv_model_path)
    meta = _load_metadata()
    meta["tabular"] = {
        "path": csv_model_path,
        "last_trained": time.time(),
        "samples": int(len(X)),
        "history": {k: [float(v) for v in vals] for k, vals in history.history.items()},
        "classes": classes,
    }
    _save_metadata(meta)
    return meta


def start_background_training(target: str = "images", epochs: int = 5, batch_size: int = 32):
    if train_lock.locked():
        raise RuntimeError("Training already in progress")

    def _runner():
        with train_lock:
            current_training["running"] = True
            current_training["status"] = "training"
            current_training["message"] = f"Training {target} model"
            current_training["started_at"] = time.time()
            current_training["ended_at"] = None
            try:
                if target == "images":
                    meta = train_image_model_from_directory(IMAGE_DIR, epochs=epochs, batch_size=batch_size)
                elif target == "csv":
                    csv_files = [os.path.join(CSV_DIR, f) for f in os.listdir(CSV_DIR) if f.lower().endswith(".csv")]
                    if not csv_files:
                        raise ValueError("No CSV files uploaded")
                    meta = train_csv_model(csv_files[-1], epochs=epochs, batch_size=batch_size)
                else:
                    raise ValueError("Invalid target")
                current_training["status"] = "completed"
                current_training["message"] = "Training completed"
                current_training["result"] = meta
            except Exception as e:
                current_training["status"] = "failed"
                current_training["message"] = str(e)
            finally:
                current_training["running"] = False
                current_training["ended_at"] = time.time()

    t = threading.Thread(target=_runner, daemon=True)
    t.start()


@app.route("/health", methods=["GET"])
def health():
    return jsonify({"ok": True, "status": "healthy"})


@app.route("/status", methods=["GET"])
def status():
    return jsonify({"ok": True, "training": current_training, "metadata": _load_metadata()})


@app.route("/upload/csv", methods=["POST"])
def upload_csv():
    if "file" not in request.files:
        return _json_error("Missing file")
    f = request.files["file"]
    try:
        path = save_uploaded_file(f, CSV_DIR, {"csv"})
    except Exception as e:
        return _json_error(str(e))
    return jsonify({"ok": True, "path": path})


@app.route("/upload/image", methods=["POST"])
def upload_image():
    if "file" not in request.files:
        return _json_error("Missing file")
    label = request.form.get("label")
    if not label:
        return _json_error("Missing label")
    f = request.files["file"]
    try:
        class_dir = os.path.join(IMAGE_DIR, secure_filename(label))
        os.makedirs(class_dir, exist_ok=True)
        filename = secure_filename(f.filename or "")
        if not filename:
            raise ValueError("Missing filename")
        if not allowed_file(filename, {"jpg", "jpeg", "png", "bmp", "webp"}):
            raise ValueError("Unsupported image type")
        unique_name = f"{uuid.uuid4().hex}_{filename}"
        path = os.path.join(class_dir, unique_name)
        f.save(path)
    except Exception as e:
        return _json_error(str(e))
    return jsonify({"ok": True, "path": path, "label": label})


@app.route("/train/images", methods=["POST"])
def train_images():
    data = request.get_json(silent=True) or {}
    epochs = int(data.get("epochs", 5))
    batch_size = int(data.get("batch_size", 32))
    try:
        start_background_training(target="images", epochs=epochs, batch_size=batch_size)
    except Exception as e:
        return _json_error(str(e), 409)
    return jsonify({"ok": True, "message": "Image training started"})


@app.route("/train/csv", methods=["POST"])
def train_csv():
    data = request.get_json(silent=True) or {}
    epochs = int(data.get("epochs", 10))
    batch_size = int(data.get("batch_size", 32))
    try:
        start_background_training(target="csv", epochs=epochs, batch_size=batch_size)
    except Exception as e:
        return _json_error(str(e), 409)
    return jsonify({"ok": True, "message": "CSV training started"})


@app.route("/predict/image", methods=["POST"])
def predict_image():
    if "file" not in request.files:
        return _json_error("Missing file")
    f = request.files["file"]
    if not os.path.exists(MODEL_PATH):
        return _json_error("Model not trained yet", 404)
    try:
        img = load_uploaded_image(f)
        meta = _load_metadata()
        model = tf.keras.models.load_model(MODEL_PATH)
        x = np.expand_dims(img, axis=0)
        preds = model.predict(x, verbose=0)[0]
        idx = int(np.argmax(preds))
        class_names = meta.get("classes", [])
        label = class_names[idx] if idx < len(class_names) else str(idx)
        return jsonify({"ok": True, "prediction": {"class": label, "index": idx, "confidence": float(preds[idx]), "probabilities": preds.tolist()}})
    except Exception as e:
        return _json_error(str(e), 500)


@app.route("/download/model", methods=["GET"])
def download_model():
    if not os.path.exists(MODEL_PATH):
        return _json_error("Model not found", 404)
    return send_from_directory(MODEL_DIR, os.path.basename(MODEL_PATH), as_attachment=True)


@app.route("/contribute/example", methods=["POST"])
def contribute_example():
    payload_type = request.form.get("type", "image")
    if payload_type == "image":
        if "file" not in request.files:
            return _json_error("Missing file")
        label = request.form.get("label")
        if not label:
            return _json_error("Missing label")
        f = request.files["file"]
        try:
            class_dir = os.path.join(IMAGE_DIR, secure_filename(label))
            os.makedirs(class_dir, exist_ok=True)
            filename = secure_filename(f.filename or "")
            if not filename:
                raise ValueError("Missing filename")
            if not allowed_file(filename, {"jpg", "jpeg", "png", "bmp", "webp"}):
                raise ValueError("Unsupported image type")
            unique_name = f"{uuid.uuid4().hex}_{filename}"
            path = os.path.join(class_dir, unique_name)
            f.save(path)
        except Exception as e:
            return _json_error(str(e))
        return jsonify({"ok": True, "message": "Contribution accepted", "path": path, "label": label})
    elif payload_type == "csv":
        if "file" not in request.files:
            return _json_error("Missing file")
        f = request.files["file"]
        try:
            path = save_uploaded_file(f, CSV_DIR, {"csv"})
        except Exception as e:
            return _json_error(str(e))
        return jsonify({"ok": True, "message": "Contribution accepted", "path": path})
    return _json_error("Unsupported contribution type")


